#include<bits/stdc++.h>
using namespace std;

int main()
{
	int a,b[2],c[2],cnt=0,g;
	cin>>a;
	while(a!=495){
		for(int i=0;i<3;i++){
			g=a%10;
			b[i]=g;
			c[i]=g;
			a/=10;
		}
		for(int i=1;i<=2;i++){
			if(b[i]>b[i-1]) swap(b[i],b[i-1]);
		}
		for(int i=1;i<=2;i++){
			if(c[i]<c[i-1]) swap(c[i],c[i-1]);
		}
		a=(b[0]-c[0])*100+(b[1]-c[1])*10+b[2]-c[2];
		cnt++;
	}
	cout<<cnt;
	return 0; 
}
